#!/usr/bin/env node

/**
 * Consolidate Fragmented Issues into Hierarchical Structure
 * 
 * This script helps reduce 648 fragmented issues to ~12 properly structured
 * hierarchical feature issues following the legal framework.
 */

const fs = require('fs');
const { execSync } = require('child_process');

class IssueConsolidator {
  constructor() {
    this.autoGeneratedIssues = [];
    this.hierarchicalIssues = [];
    this.toClose = [];
    this.toKeep = [];
  }

  /**
   * Identify auto-generated issues that need consolidation
   */
  identifyAutoGeneratedIssues() {
    console.log('🔍 Identifying auto-generated issues...\n');
    
    try {
      // Get all open issues
      const output = execSync(
        'gh api repos/cogpy/ad-res-j7/issues?state=open&per_page=100 --paginate',
        { encoding: 'utf8' }
      );
      
      const issues = JSON.parse(output);
      console.log(`📊 Total open issues: ${issues.length}\n`);
      
      // Categorize issues
      issues.forEach(issue => {
        const labels = issue.labels.map(l => l.name);
        const title = issue.title;
        const body = issue.body || '';
        
        // Identify auto-generated issues from workflows
        const isAutoGenerated = 
          labels.includes('todo') ||
          labels.includes('enhancement') ||
          body.includes('Generated automatically from todo files') ||
          body.includes('Created from repository item') ||
          body.includes('Source File:') ||
          title.includes('Priority 1') ||
          title.includes('Priority 2') ||
          title.includes('Priority 3') ||
          title.includes('Priority 4') ||
          title.includes('PARA_') ||
          title.includes('Improvements Needed') ||
          title.length < 30; // Very short titles are likely fragments
        
        // Identify hierarchical issues (properly structured)
        const isHierarchical = 
          labels.includes('feature') ||
          labels.includes('legal-argument') ||
          labels.includes('hierarchical') ||
          title.startsWith('[FEATURE') ||
          title.startsWith('[PARA') ||
          title.startsWith('[TASK');
        
        if (isHierarchical) {
          this.hierarchicalIssues.push(issue);
          this.toKeep.push(issue);
        } else if (isAutoGenerated) {
          this.autoGeneratedIssues.push(issue);
          this.toClose.push(issue);
        } else {
          // Manual issues or important ones - keep
          this.toKeep.push(issue);
        }
      });
      
      console.log('📋 Classification Results:');
      console.log(`  ✅ Hierarchical (keep): ${this.hierarchicalIssues.length}`);
      console.log(`  🗑️  Auto-generated (close): ${this.autoGeneratedIssues.length}`);
      console.log(`  📌 Other (keep): ${this.toKeep.length - this.hierarchicalIssues.length}`);
      console.log(`  📊 Total to keep: ${this.toKeep.length}`);
      console.log(`  📊 Total to close: ${this.toClose.length}\n`);
      
    } catch (error) {
      console.error('❌ Error identifying issues:', error.message);
      throw error;
    }
  }

  /**
   * Generate report of what will be closed
   */
  generateReport() {
    console.log('📝 Generating consolidation report...\n');
    
    const report = {
      timestamp: new Date().toISOString(),
      summary: {
        total_open_issues: this.autoGeneratedIssues.length + this.toKeep.length,
        hierarchical_issues: this.hierarchicalIssues.length,
        auto_generated_to_close: this.autoGeneratedIssues.length,
        issues_to_keep: this.toKeep.length,
        estimated_final_count: this.toKeep.length
      },
      issues_to_close: this.toClose.map(i => ({
        number: i.number,
        title: i.title,
        labels: i.labels.map(l => l.name),
        url: i.html_url,
        created_at: i.created_at
      })),
      hierarchical_issues: this.hierarchicalIssues.map(i => ({
        number: i.number,
        title: i.title,
        labels: i.labels.map(l => l.name),
        url: i.html_url
      })),
      issues_to_keep: this.toKeep.map(i => ({
        number: i.number,
        title: i.title,
        labels: i.labels.map(l => l.name),
        url: i.html_url
      }))
    };
    
    fs.writeFileSync('issue-consolidation-report.json', JSON.stringify(report, null, 2));
    console.log('✅ Report saved to issue-consolidation-report.json\n');
    
    return report;
  }

  /**
   * Close auto-generated issues with explanation
   */
  closeAutoGeneratedIssues(dryRun = true) {
    console.log(`${dryRun ? '🔍 DRY RUN:' : '🗑️'} Closing auto-generated issues...\n`);
    
    const closeMessage = `This issue is being closed as part of a repository-wide consolidation effort.

**Reason**: This issue was auto-generated from todo files and created fragmented, granular issues instead of properly structured hierarchical issues.

**Next Steps**: The work described in this issue has been consolidated into properly structured feature issues following the hierarchical legal framework (Legal Arguments → Features → Paragraphs → Tasks).

**See**: 
- HIERARCHICAL_ISSUES_SUMMARY.md for the proper structure
- Labels: \`feature\`, \`legal-argument\`, \`hierarchical\` for consolidated issues

This consolidation reduces 648 fragmented issues to ~10-15 properly structured feature issues.`;

    let closedCount = 0;
    let failedCount = 0;
    
    for (const issue of this.toClose.slice(0, dryRun ? 10 : undefined)) {
      try {
        console.log(`  ${dryRun ? '[DRY RUN]' : 'Closing'} #${issue.number}: ${issue.title.substring(0, 60)}...`);
        
        if (!dryRun) {
          // Add comment explaining closure
          execSync(
            `gh issue comment ${issue.number} --body "${closeMessage.replace(/\\/g, '\\\\').replace(/"/g, '\\"')}"`,
            { encoding: 'utf8', stdio: 'pipe' }
          );
          
          // Close the issue
          execSync(
            `gh issue close ${issue.number} --reason "not planned"`,
            { encoding: 'utf8', stdio: 'pipe' }
          );
          
          closedCount++;
          
          // Rate limiting delay
          if (closedCount % 10 === 0) {
            console.log('    ⏸️  Pausing to avoid rate limits...');
            execSync('sleep 2');
          }
        } else {
          closedCount++;
        }
      } catch (error) {
        console.error(`    ❌ Failed to close #${issue.number}:`, error.message);
        failedCount++;
      }
    }
    
    console.log(`\n${dryRun ? 'Would close' : 'Closed'}: ${closedCount} issues`);
    if (failedCount > 0) {
      console.log(`Failed: ${failedCount} issues`);
    }
    
    if (dryRun && this.toClose.length > 10) {
      console.log(`\n⚠️  This was a dry run showing first 10 issues.`);
      console.log(`   Total issues to close: ${this.toClose.length}`);
      console.log(`   Run with --execute to actually close issues.\n`);
    }
  }

  /**
   * Display summary of current state
   */
  displaySummary() {
    console.log('\n' + '='.repeat(70));
    console.log('📊 ISSUE CONSOLIDATION SUMMARY');
    console.log('='.repeat(70) + '\n');
    
    console.log('Current State:');
    console.log(`  📈 Total open issues: ${this.autoGeneratedIssues.length + this.toKeep.length}`);
    console.log(`  🗑️  Auto-generated (to close): ${this.autoGeneratedIssues.length}`);
    console.log(`  ✅ Issues to keep: ${this.toKeep.length}`);
    console.log('');
    
    console.log('After Consolidation:');
    console.log(`  📊 Estimated final count: ${this.toKeep.length}`);
    console.log(`  🎯 Target: 10-15 feature issues`);
    console.log(`  📉 Reduction: ${this.autoGeneratedIssues.length} issues removed`);
    console.log('');
    
    if (this.toKeep.length > 20) {
      console.log('⚠️  Warning: Final count still high.');
      console.log('   Recommend reviewing remaining issues for further consolidation.');
    } else if (this.toKeep.length <= 15) {
      console.log('✅ Target achieved: Issue count within expected range!');
    }
    
    console.log('\n' + '='.repeat(70) + '\n');
  }
}

/**
 * Main CLI
 */
async function main() {
  const args = process.argv.slice(2);
  const command = args[0];
  
  console.log('🔧 Issue Consolidation Tool');
  console.log('===========================\n');
  
  const consolidator = new IssueConsolidator();
  
  try {
    // Always identify issues first
    consolidator.identifyAutoGeneratedIssues();
    
    switch (command) {
      case 'report':
        consolidator.generateReport();
        consolidator.displaySummary();
        break;
        
      case 'dry-run':
        consolidator.generateReport();
        consolidator.closeAutoGeneratedIssues(true);
        consolidator.displaySummary();
        break;
        
      case 'execute':
        console.log('⚠️  WARNING: This will close issues permanently!\n');
        consolidator.generateReport();
        
        // Require confirmation
        const confirmFile = 'CONFIRM_CLOSE_ISSUES.txt';
        if (!fs.existsSync(confirmFile)) {
          console.log('❌ Confirmation required!');
          console.log('');
          console.log('To execute, create a file named CONFIRM_CLOSE_ISSUES.txt with:');
          console.log('  echo "I confirm closing auto-generated issues" > CONFIRM_CLOSE_ISSUES.txt');
          console.log('');
          console.log('Then run: node scripts/consolidate-issues-to-hierarchy.js execute');
          process.exit(1);
        }
        
        console.log('✅ Confirmation found. Proceeding...\n');
        consolidator.closeAutoGeneratedIssues(false);
        consolidator.displaySummary();
        
        // Clean up confirmation file
        fs.unlinkSync(confirmFile);
        break;
        
      default:
        console.log('Usage:');
        console.log('  node scripts/consolidate-issues-to-hierarchy.js report     - Generate report only');
        console.log('  node scripts/consolidate-issues-to-hierarchy.js dry-run    - Preview what will be closed');
        console.log('  node scripts/consolidate-issues-to-hierarchy.js execute    - Actually close issues (requires confirmation)');
        console.log('');
        console.log('Examples:');
        console.log('  node scripts/consolidate-issues-to-hierarchy.js report');
        console.log('  node scripts/consolidate-issues-to-hierarchy.js dry-run');
        process.exit(0);
    }
    
  } catch (error) {
    console.error('\n❌ Fatal error:', error.message);
    process.exit(1);
  }
}

// Run if called directly
if (require.main === module) {
  main().catch(error => {
    console.error('Fatal error:', error);
    process.exit(1);
  });
}

module.exports = IssueConsolidator;
